184→// ============== 单位升阶 ==============
185→
186→TArray<FLFPUnitEntry> ULFPGameInstance::GetMergeablePairs() const
187→{
188→	// 统计所有单位的 {TypeID, Tier} 出现次数
189→	TMap<FName, TMap<int32, int32>> CountMap; // TypeID → (Tier → Count)
190→
191→	for (const FLFPUnitEntry& Unit : PartyUnits)
192→	{
193→		if (Unit.IsValid())
194→		{
195→			CountMap.FindOrAdd(Unit.TypeID).FindOrAdd(Unit.Tier, 0)++;
196→		}
197→	}
198→	for (const FLFPUnitEntry& Unit : ReserveUnits)
199→	{
200→		if (Unit.IsValid())
201→		{
202→			CountMap.FindOrAdd(Unit.TypeID).FindOrAdd(Unit.Tier, 0)++;
203→		}
204→	}
205→
206→	// 筛选出现 >= 2 次且 Tier < MaxUnitTier 的组合
207→	TArray<FLFPUnitEntry> Result;
208→	for (const auto& TypePair : CountMap)
209→	{
210→		for (const auto& TierPair : TypePair.Value)
211→		{
212→			if (TierPair.Value >= 2 && TierPair.Key < MaxUnitTier)
213→			{
214→				FLFPUnitEntry Entry;
215→				Entry.TypeID = TypePair.Key;
216→				Entry.Tier = TierPair.Key;
217→				Result.Add(Entry);
218→			}
219→		}
220→	}
221→
222→	return Result;
223→}
