225→bool ULFPGameInstance::MergeUnits(bool bSourceAIsParty, int32 SourceAIndex, bool bSourceBIsParty, int32 SourceBIndex)
226→{
227→	// 获取源单位引用
228→	TArray<FLFPUnitEntry>& ArrayA = bSourceAIsParty ? PartyUnits : ReserveUnits;
229→	TArray<FLFPUnitEntry>& ArrayB = bSourceBIsParty ? PartyUnits : ReserveUnits;
230→
231→	if (!ArrayA.IsValidIndex(SourceAIndex) || !ArrayB.IsValidIndex(SourceBIndex))
232→	{
233→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 无效的槽位索引"));
234→		return false;
235→	}
236→
237→	const FLFPUnitEntry& UnitA = ArrayA[SourceAIndex];
238→	const FLFPUnitEntry& UnitB = ArrayB[SourceBIndex];
239→
240→	// 验证匹配条件
241→	if (UnitA.TypeID != UnitB.TypeID || UnitA.Tier != UnitB.Tier)
242→	{
243→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 单位不匹配 (%s T%d vs %s T%d)"),
244→			*UnitA.TypeID.ToString(), UnitA.Tier, *UnitB.TypeID.ToString(), UnitB.Tier);
245→		return false;
246→	}
247→
248→	if (UnitA.Tier >= MaxUnitTier)
249→	{
250→		UE_LOG(LogTemp, Warning, TEXT("MergeUnits: 已达最大阶级 %d"), MaxUnitTier);
251→		return false;
252→	}
253→
254→	// 创建升阶后的新单位
255→	FLFPUnitEntry NewUnit;
256→	NewUnit.TypeID = UnitA.TypeID;
257→	NewUnit.Tier = UnitA.Tier + 1;
258→
259→	// 移除两个源单位（注意索引偏移：同一数组时先移除大索引）
260→	if (bSourceAIsParty == bSourceBIsParty)
261→	{
262→		// 同一数组，先移除大索引
263→		int32 First = FMath::Max(SourceAIndex, SourceBIndex);
264→		int32 Second = FMath::Min(SourceAIndex, SourceBIndex);
265→		ArrayA.RemoveAt(First);
266→		ArrayA.RemoveAt(Second);
267→	}
268→	else
269→	{
270→		// 不同数组，顺序无所谓
271→		ArrayA.RemoveAt(SourceAIndex);
272→		ArrayB.RemoveAt(SourceBIndex);
273→	}
274→
275→	// 添加新单位
276→	TryAddUnit(NewUnit);
277→
278→	UE_LOG(LogTemp, Log, TEXT("升阶成功: %s T%d + T%d → T%d"),
279→		*NewUnit.TypeID.ToString(), NewUnit.Tier - 1, NewUnit.Tier - 1, NewUnit.Tier);
280→
281→	return true;
282→}
